```tsx
import React from 'react';
import { Message, Role } from '../types';
import MarkdownRenderer from './MarkdownRenderer';
import { Bot, User } from 'lucide-react';

interface MessageBubbleProps {
  message: Message;
}

const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const isUser = message.role === Role.User;
  const hasAttachment = message.attachment && message.attachment.url;

  return (
    <div className="flex w-full py-2">
      <div className={`flex w-full ${isUser ? 'justify-end' : 'justify-start'}`}>
        <div className="flex items-end max-w-[70%]">
          {/* Avatar */}
          <div className="pr-2">
            {isUser ? <User className="h-6 w-6" /> : <Bot className="h-6 w-6" />}
          </div>
          <div className="flex flex-col">
            <div className={`relative px-5 py-3.5 rounded-2xl shadow-sm text-sm md:text-base ${
              isUser
                ? 'bg-[#e3f2fd] text-gray-900 rounded-tr-none'
                : 'bg-white border border-gray-100 text-gray-800 rounded-tl-none'
            }`}>
              <MarkdownRenderer content={message.text} />
              {hasAttachment && (
                <img
                  src={message.attachment.url}
                  alt="Attachment"
                  className="mt-2 rounded-md max-w-full h-auto"
                  style={{ maxWidth: '100%', maxHeight: '200px' }}
                />
              )}
            </div>

            {/* Timestamp */}
            <span className="text-[10px] text-gray-400 px-1">
              {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MessageBubble;
```


